from __future__ import annotations

from dataclasses import dataclass
from typing import Any

AKSHARE_DOCS_INDEX_URL = "https://akshare.akfamily.xyz/data/index.html"


@dataclass(frozen=True, slots=True)
class AkShareDatasetSpec:
    dataset: str
    function_name: str
    title: str
    domain: str
    category: str
    tags: tuple[str, ...]
    input_fields: tuple[str, ...]
    required_fields: tuple[str, ...]
    doc_url: str
    realtime: bool
    default_limit: int = 200

    def to_dict(self, *, compact: bool = False) -> dict[str, Any]:
        payload = {
            "dataset": self.dataset,
            "function_name": self.function_name,
            "title": self.title,
            "domain": self.domain,
            "category": self.category,
            "tags": list(self.tags),
            "input_fields": list(self.input_fields),
            "required_fields": list(self.required_fields),
            "doc_url": self.doc_url,
            "realtime": self.realtime,
            "default_limit": self.default_limit,
        }
        if compact:
            payload["tags"] = payload["tags"][:6]
            payload["input_fields"] = payload["input_fields"][:8]
            payload["required_fields"] = payload["required_fields"][:8]
        return payload


